const body = $input.first().json.body || $input.first().json;
const message = body.entry?.[0]?.changes?.[0]?.value?.messages?.[0];

if (!message || message.type !== 'text') {
  return [{ json: { action: 'ignore' } }];
}

const text = message.text.body.trim().toLowerCase();
const from = message.from;

let action = 'unknown';
let taskNum = null;
let taskTitle = null;

const doneMatch = text.match(/^done\s*(\d+)/);
const addMatch = text.match(/^(?:add|focus)\s+(.+)/);

if (doneMatch) {
  action = 'complete';
  taskNum = parseInt(doneMatch[1]);
} else if (addMatch) {
  action = 'add';
  taskTitle = addMatch[1];
} else if (text === 'tasks' || text === 'status') {
  action = 'list';
}

return [{ json: { action, taskNum, taskTitle, from } }];

const data = $('Parse Command').first().json;
const action = data.action;

const API = 'http://backend:8000';

if (action === 'complete') {
  // Fetch tasks, find the Nth one, mark done
  const resp = await fetch(API + '/tasks/?status=pending');
  const tasks = await resp.json();
  const sorted = tasks.sort((a, b) => b.priority_score - a.priority_score);
  const task = sorted[data.taskNum - 1];
  if (!task) return [{ json: { reply: 'No task #' + data.taskNum + '. You have ' + sorted.length + ' tasks.' } }];
  await fetch(API + '/tasks/' + task.id, { method: 'PATCH', headers: {'Content-Type': 'application/json'}, body: JSON.stringify({status: 'done'}) });
  return [{ json: { reply: '✅ Done: ' + task.title } }];
}

if (action === 'add') {
  await fetch(API + '/tasks/', { method: 'POST', headers: {'Content-Type': 'application/json'}, body: JSON.stringify({title: data.taskTitle, priority_score: 7.0, status: 'pending', estimated_minutes: 30}) });
  return [{ json: { reply: '➕ Added: ' + data.taskTitle } }];
}

if (action === 'list') {
  const resp = await fetch(API + '/tasks/?status=pending');
  const tasks = await resp.json();
  const sorted = tasks.sort((a, b) => b.priority_score - a.priority_score);
  const list = sorted.map((t, i) => (i+1) + '. ' + t.title + ' (' + t.priority_score.toFixed(1) + ')').join('\n');
  return [{ json: { reply: '*Your Tasks:*\n\n' + (list || 'No pending tasks.') } }];
}

return [{ json: { reply: 'Commands: done 1, add [task], tasks' } }];
